import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2023 - Present",
    description:
      "Lidero la estrategia global para la plataforma financiera y de investigación.",
    icon: <FaBriefcase />,
  },
  {
    title: "Product Manager",
    company: "J.P. Morgan",
    date: "2019 - 2023",
    description: "Implementé soluciones cloud y event-driven para banca global.",
    icon: <FaCloud />,
  },
  {
    title: "IT Consultant",
    company: "Telecom Argentina",
    date: "2010 - 2019",
    description: "Proyectos de transformación digital y automatización.",
    icon: <FaUniversity />,
  },
];

export default function ExperienceTimeline() {
  return (
    <VerticalTimeline>
      {experienceData.map((exp, idx) => (
        <VerticalTimelineElement
          key={idx}
          date={exp.date}
          iconStyle={{ background: "#6b46c1", color: "#fff" }}
          contentStyle={{ background: "#6b46c1", color: "#fff" }}
          contentArrowStyle={{ borderRight: "7px solid #6b46c1" }}
          icon={exp.icon}
        >
          <h3>{exp.title}</h3>
          <h4>{exp.company}</h4>
          <p>{exp.description}</p>
        </VerticalTimelineElement>
      ))}
    </VerticalTimeline>
  );
}
